#include<bits/stdc++.h>
using namespace std;
int n,k,dp[2][35010][3],tr1[101],tr2[101];
const long long mod=1e9+7;
long long ans[101];
char s[110];
int encode(int a[])
{
    int ans=0;
    for(int i=0;i<k;i++)
    {
        ans|=(a[i+1]-a[i])<<i;
    }
    return ans;
}
void decode(int a[],int val)
{
    for(int i=0;i<k;i++)
    {
        a[i+1]=(val>>i)&1;
    }
    for(int i=1;i<=k;i++)
    {
        a[i]+=a[i-1];
    }
}
void f(int ti,int cf,int tj,char ch,long long val)
{
    decode(tr1,cf);
    for(int i=1;i<=k;i++)
    {
        tr2[i]=max({tr2[i-1],tr1[i],tr1[i-1]+(int)(ch==s[i])});
    }
    int p=encode(tr2);
    dp[ti][p][tj]+=val;
    dp[ti][p][tj]%=mod;
}
int main()
{
    scanf("%d%d%s",&n,&k,s+1);
    dp[0][0][0]=1;
    for(int i=0;i<n;i++)
    {
        int nxt=1-i%2,now=i%2;
        for(int j=0;j<(1<<k);j++)
        {
            for(int p=0;p<3;p++)
            {
                dp[nxt][j][p]=0;
            }
        }
        for(int j=0;j<(1<<k);j++)
        {
            if(dp[now][j][0])
            {
                f(nxt,j,1,'N',dp[now][j][0]);
                f(nxt,j,0,'O',dp[now][j][0]);
                f(nxt,j,0,'I',dp[now][j][0]);
            }
            if(dp[now][j][1])
            {
                f(nxt,j,1,'N',dp[now][j][1]);
                f(nxt,j,2,'O',dp[now][j][1]);
                f(nxt,j,0,'I',dp[now][j][1]);
            }
            if(dp[now][j][2])
            {
                f(nxt,j,1,'N',dp[now][j][2]);
                f(nxt,j,0,'O',dp[now][j][2]);
            }
        }
    }
    for(int i=0;i<(1<<k);i++)
    {
        for(int j=0;j<3;j++)
        {
            ans[__builtin_popcount(i)]+=dp[n%2][i][j];
            ans[__builtin_popcount(i)]%=mod;
        }
    }
    for(int i=0;i<=k;i++)
    {
        printf("%d\n",ans[i]);
    }
    return 0;
}
